    const secrets: Secret[] = [
      makeSecret({ name: "old", lastRotated: "2026-01-01", rotationPolicyDays: 30 }),
      makeSecret({ name: "older", lastRotated: "2025-01-01", rotationPolicyDays: 30 }),
    ];
