    expects: [
      "POLICY_OK",
      // Markdown report sections
      "## Expired (0)",
      "## Warning (0)",
      "## OK (1)",
      "| well-rested-key |",
      // JSON summary fields exact
      `"total": 1`,
      `"expired": 0`,
      `"warning": 0`,
      `"ok": 1`,
      `"status": "ok"`,
