  for (const f of [
    "validator.ts",
    "validator.test.ts",
    "package.json",
    "tsconfig.json",
    ".github",
    "fixtures",
  ]) {
    cpSync(join(PROJECT_ROOT, f), join(workdir, f), { recursive: true });
  }
  // Initialize a git repo (act expects one).
  for (const cmd of [
    ["git", "init", "-q", "-b", "main"],
    ["git", "config", "user.email", "test@example.com"],
    ["git", "config", "user.name", "Test"],
    ["git", "add", "."],
    ["git", "commit", "-q", "-m", "init"],
